            }

            var uploadsFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", UploadFolder);
            if (!Directory.Exists(uploadsFolder))
            {
                Directory.CreateDirectory(uploadsFolder);
            }

